// Custom n8n Function Node before API Action
import { Vex } from '@vex_dev/sdk';
const vex = new Vex('YOUR_VEX_API_KEY');

const toolParams = $json.toolParameters;
const check = await vex.check({
  session: $json.sessionId,
  input: JSON.stringify(toolParams),
  rules: [
    'no_api_keys',
    'no_pii_in_params',
    'credential_sanitization'
  ],
  context: {
    sensitiveFields: ['apiKey', 'password', 'bearerToken'],
    atsSystem: 'greenhouse'
  }
});

if (check.violations.length > 0) {
  $json.error = `Credential exposure detected: ${check.violations.join(', ')}`;
  return [];
}

// Safe to proceed to API call
$json.safeParams = check.sanitizedInput;
